def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_score = 70 + np.log1p(cap) * 30 + np.exp(-usage)
        oscillate = 0.0
        decay = 0.0
        aggressive_boost = 0.0
        fine_tune = 0.0
        modifier = 1.0
        if usage > 5:
            base_score += 6000 * np.power(usage, 1.3)
            if cap > 15:
                base_score += 120 * np.cbrt(cap) + 50 * np.cos(cap * 1.7)
            else:
                base_score -= 45 * usage
            for i in range(1, 6):
                oscillate += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 25 / (i + 1)
            decay = np.exp(-usage / 7) * 500
            aggressive_boost = np.log(cap + 1) * 200 if cap % 2 < 1 else -100
        elif 4 < usage <= 5:
            diff = usage - 4
            base_score += 2200 * diff ** 2 + 180 * (1 - np.sqrt(diff))
            for j in range(1, 9):
                oscillate += np.cos(usage * np.pi * (j ** 1.5)) * 30 / j
            if int(cap * 4) % 5 == 1:
                base_score += 55 * np.tan(cap / 12)
            decay = 200 * np.exp(-diff)
        elif 3 < usage <= 4:
            base_score += 1500 * (usage - 3) ** 2.3
            for k in range(1, 13):
                val = usage ** k
                if val < 0.3:
                    oscillate += val * 12 / k
                    if k % 4 == 0:
                        oscillate += 5 * k
                else:
                    oscillate += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.5:
                        oscillate += 30
            if cap % 2.7 < 0.7:
                base_score += 40 * np.sin(cap * 2.8)
            decay = 120 * np.exp(-usage)
        elif 2 < usage <= 3:
            base_score += 1100 * (usage - 2) ** 3
            for m in range(1, 17):
                val = usage ** m
                if val < 0.5:
                    oscillate += val * 20 / m
                    if m % 6 == 2:
                        oscillate -= 3 * m
                else:
                    oscillate += (1 - val) * 15 / (m + 4)
                    if m == 14 and usage > 2.7:
                        oscillate += 25
            if cap % 1.9 < 0.6:
                base_score += 30 * np.cos(cap * 3.5)
            decay = 85 * np.exp(-usage / 1.5)
        elif 1 < usage <= 2:
            base_score += 950 * (usage - 1) ** 2.8
            for n in range(1, 20):
                val = usage ** n
                if val < 0.65:
                    oscillate += val * 22 / n
                    if n % 5 == 0:
                        oscillate -= 4 * n
                else:
                    oscillate += (1 - val) * 10 / (n + 5)
                    if n == 18 and usage > 1.8:
                        oscillate += 18
            if cap % 1.3 < 0.4:
                base_score += 35 * np.sin(cap * 2.3)
            decay = 65 * np.exp(-usage / 2)
        elif 0.3 < usage <= 1:
            base_score += 140 * (1 - usage) * (1 + np.cos(usage * np.pi))
            for o in range(1, 13):
                val = usage ** o
                oscillate += (np.tanh(val * np.pi / 3) - 0.4) * 15 / o
                if usage < 0.05 * o:
                    oscillate -= 10 * o
            if cap < 0.1:
                base_score += np.sqrt(cap) * 300
            elif cap < 0.7:
                base_score += np.log1p(cap * 25) * 40
            else:
                base_score += (cap % 7) * 25
            decay = 35 * np.exp(-usage * 5)
        else:
            base_score += 300 * (1 - usage) ** 3
            for p in range(1, 20):
                val = usage ** p
                oscillate += (np.sin(val * np.pi / 5) - 0.3) * 14 / p
                if usage < 0.01 * p:
                    oscillate -= 15 * p
            if cap < 0.01:
                base_score += np.sqrt(cap) * 350
            elif cap < 0.8:
                base_score += np.log1p(cap * 30) * 50
            else:
                base_score += (cap % 7) * 35
            decay = 25 * np.exp(-usage * 3)
        priority = base_score + oscillate + decay + aggressive_boost
        if cap < 0.03:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.2:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1400) % (s + 5) == 0:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.15:
                priority -= 50
                for t in range(1, 8):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 110
                for u in range(1, 6):
                    priority += u * 15
            else:
                priority += 40
        eccentricity = 0
        if int(cap * 3000) % 21 == 0:
            eccentricity += 20
        if int(cap * 1000) % 27 == 0:
            eccentricity -= 15
        if int(cap * 250) % 11 == 0:
            eccentricity += 18
        for w in range(1, 11):
            diff = abs(usage - w / 10)
            if diff < 0.015:
                eccentricity += 25 / w
            elif diff < 0.04:
                eccentricity += 13 / w
            else:
                eccentricity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 10)
            if mod_chk == 0:
                eccentricity += x * 6
            elif mod_chk == 4:
                eccentricity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 2000) % (y + 7)
            if mod_chk == 0:
                eccentricity += 15 * y
            elif mod_chk == 4:
                eccentricity -= 10 * y
        priority += eccentricity
        if usage < 0.003:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 14
        if cap > 3.0:
            if cap % 1 < 0.08:
                priority += 55
            if (int(cap * 3000) % 27 == 0) and (usage > 0.75):
                priority += 80
            for bb in range(1, 8):
                if (int(cap * 700) % (bb + 10) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
